// ── Flutter widget style ───────────────────
Widget buildCard({
  required String title,
  required String subtitle,
  Widget? trailing,
  VoidCallback? onTap,
}) {
  return ListTile(
    title: Text(title),
    subtitle: Text(subtitle),
    trailing: trailing,
    onTap: onTap,
  );
}

